// Normalize Google News (or any RSS) entries -> latest_updates rows, keeping
// only health items. Google News titles look like 'Headline - Publisher', so
// we split the publisher off into source_name. These feeds carry no image, so
// image_url is left null and the app fills a themed local image at render.
const RX = /\b(dengue|covid|coronavirus|vaccin\w*|influenza|flu|virus\w*|hospitals?|outbreaks?|diseases?|measles|hfmd|mosquito\w*|infections?|healthcare|health|wellness|booster|epidemic|pandemic|fever|diabetes|cancer|MOH|NEA|HSA|HPB)\b/i;
function pickImg(o){ if(!o) return null; if(typeof o==='string') return o; return (o.$ && o.$.url) || o.url || null; }
const rows = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const link = j.link || j.guid;
  let title = (j.title || '').trim();
  if (!link || !title) continue;
  let source = j.creator || '';
  const m = title.match(/^(.*?)\s+-\s+([^-]+)$/);
  if (m) { title = m[1].trim(); if (!source) source = m[2].trim(); }
  if (!RX.test(title + ' ' + (j.contentSnippet || ''))) continue; // health-only filter
  rows.push({
    title: title.slice(0, 300),
    summary: null,
    source_name: (source || 'Google News').slice(0, 60),
    source_url: link,
    category: 'Health',
    location: 'Singapore',
    severity: null,
    image_url: pickImg(j.enclosure) || pickImg(j['media:thumbnail']) || pickImg(j['media:content']) || null,
    published_at: j.isoDate || j.pubDate || null
  });
}
return rows.map((r) => ({ json: r }));

// De-dupe by source_url and emit a single array so the upsert is one request.
// Supabase's UNIQUE(source_url) is the final guard.
const seen = new Set();
const rows = [];
for (const item of $input.all()) {
  const r = item.json;
  if (!r || !r.source_url || seen.has(r.source_url)) continue;
  seen.add(r.source_url);
  rows.push(r);
}
return [{ json: { rows: rows.slice(0, 15) } }];
